#include<bits/stdc++.h>
using namespace std;

int main() {
	long long a[10001], n, mina = 999999999999999, m, num;
	cin >> n >> m;
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}
	for (int i = 0; i <= n - m; i++) {
		num = 0;
		for (int j = i; j < i+m; j++) {
			num += a[j];
		}
		mina = min(num, mina);
	}
	cout << mina;
	return 0;
}
